@app.route('/setup-mfa', methods=['GET', 'POST'])
@login_required
def setup_mfa():
    if request.method == 'GET':
        if not current_user.has_mfa_enabled():
            new_secret = pyotp.random_base32()
            session['mfa_setup_secret'] = new_secret # Store temporarily
            
            totp_uri = pyotp.totp.TOTP(new_secret).provisioning_uri(
                name=current_user.username,
                issuer_name="Flask MFA Demo"
            )
            
            img = qrcode.make(totp_uri)
            buffer = BytesIO()
            img.save(buffer, format="PNG")
            qr_code_base64 = base64.b64encode(buffer.getvalue()).decode("utf-8")

            return render_template('mfa_setup.html', new_secret=new_secret, qr_code_base64=qr_code_base64)
        else:
            flash('MFA is already enabled for your account.', 'info')
            return render_template('mfa_setup.html', mfa_enabled=True)

    elif request.method == 'POST':
        action = request.form.get('action')

        if action == 'enable':
            mfa_code = request.form.get('mfa_code')
            setup_secret = session.get('mfa_setup_secret')

            if not setup_secret:
                flash('MFA setup session expired or invalid.', 'danger')
                return redirect(url_for('setup_mfa'))

            totp = pyotp.TOTP(setup_secret)
            if totp.verify(mfa_code):
                current_user.mfa_secret = setup_secret
                users[current_user.id].mfa_secret = setup_secret # Update in-memory DB
                session.pop('mfa_setup_secret', None)
                session['mfa_verified'] = True # Once setup, it's considered verified
                flash('MFA has been successfully enabled!', 'success')
                return redirect(url_for('dashboard'))
            else:
                flash('Invalid MFA code. Please try again.', 'danger')
                # Re-render setup with same secret for retry
                totp_uri = pyotp.totp.TOTP(setup_secret).provisioning_uri(
                    name=current_user.username,
                    issuer_name="Flask MFA Demo"
                )
                img = qrcode.make(totp_uri)
                buffer = BytesIO()
                img.save(buffer, format="PNG")
                qr_code_base64 = base64.b64encode(buffer.getvalue()).decode("utf-8")
                return render_template('mfa_setup.html', new_secret=setup_secret, qr_code_base64=qr_code_base64)

        elif action == 'disable':
            current_user.mfa_secret = None
            users[current_user.id].mfa_secret = None # Update in-memory DB
            session.pop('mfa_setup_secret', None)
            session['mfa_verified'] = True # If MFA is disabled, it's 'verified' by default
            flash('MFA has been successfully disabled.', 'info')
            return redirect(url_for('dashboard'))

    return redirect(url_for('dashboard')) # Fallback

